import requests

def test_payroll_run_rate_limit_at_threshold_boundary(
    hr_admin_token, reset_rate_limit, rate_limit_config, api_base_url
):
    headers = {"Authorization": f"Bearer {hr_admin_token}"}
    limit = rate_limit_config["payroll_run_per_window"]

    statuses = []
    for i in range(limit):
        payload = {"period": f"2024-{7 + i:02d}", "type": "monthly"}
        r = requests.post(f"{api_base_url}/api/payroll-runs", json=payload, headers=headers)
        statuses.append(r.status_code)

    assert all(s in (201, 202, 409) for s in statuses), (
        f"Unexpected status within limit: {statuses}"
    )

    overflow_payload = {"period": f"2024-{7 + limit:02d}", "type": "monthly"}
    overflow_resp = requests.post(
        f"{api_base_url}/api/payroll-runs", json=overflow_payload, headers=headers
    )
    assert overflow_resp.status_code == 429
    assert "retry-after" in {k.lower() for k in overflow_resp.headers}
